/** Client-side CSV export for ERP master catalog lists (parity MM export-excel phase 2). */
export function downloadCatalogCsv(
  fileName: string,
  headers: string[],
  rows: Array<Array<string | number | boolean | null | undefined>>,
): void {
  const escape = (v: string) => `"${v.replace(/"/g, '""')}"`;
  const toCell = (v: string | number | boolean | null | undefined) => {
    if (v == null) return '';
    if (typeof v === 'boolean') return v ? 'Đang dùng' : 'Ngưng';
    return String(v);
  };
  const csv = [headers, ...rows]
    .map(r => r.map(c => escape(toCell(c))).join(','))
    .join('\n');
  const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = fileName.endsWith('.csv') ? fileName : `${fileName}.csv`;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}
